import{_ as a,o as i,c as o,ag as n}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Transformadores","description":"","frontmatter":{},"headers":[],"relativePath":"es/power-systems/distribution/transformers.md","filePath":"es/power-systems/distribution/transformers.md"}'),s={name:"es/power-systems/distribution/transformers.md"};function r(t,e,l,c,d,p){return i(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="transformadores" tabindex="-1">Transformadores <a class="header-anchor" href="#transformadores" aria-label="Permalink to &quot;Transformadores&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>Los transformadores son dispositivos eléctricos utilizados para cambiar los niveles de voltaje en sistemas de potencia.</p><p>Permiten transferir energía entre circuitos a diferentes niveles de voltaje manteniendo la misma frecuencia.</p><p>Los transformadores son esenciales para conectar la distribución en media tensión con los sistemas de baja tensión y para adaptar la energía a los requisitos de diferentes equipos.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>El propósito de los transformadores es:</p><ul><li>Reducir el voltaje para uso seguro del equipo</li><li>Elevar el voltaje para transmisión y distribución eficientes</li><li>Proporcionar aislamiento eléctrico entre circuitos</li><li>Adaptar los niveles de potencia a los requisitos del sistema</li></ul><p>Sin transformadores, la distribución eficiente de energía y su utilización segura no serían posibles.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>Los transformadores operan basándose en la inducción electromagnética.</p><p>Consisten en dos devanados principales:</p><ul><li>Devanado primario conectado al voltaje de entrada</li><li>Devanado secundario conectado a la salida</li></ul><p>Cuando la corriente alterna fluye a través del devanado primario, crea un campo magnético en el núcleo.</p><p>Este campo magnético variable induce un voltaje en el devanado secundario.</p><p>La relación de voltaje depende del número de espiras en cada devanado:</p><ul><li>Más espiras en el secundario resultan en mayor voltaje de salida</li><li>Menos espiras en el secundario resultan en menor voltaje de salida</li></ul><p>La energía se transfiere magnéticamente, sin conexión eléctrica directa entre los devanados.</p><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>Los transformadores se utilizan en:</p><ul><li>Reducción de media tensión a baja tensión en instalaciones industriales</li><li>Alimentación de tableros de control y sistemas auxiliares</li><li>Subestaciones de distribución de energía dentro de plantas</li><li>Aislamiento de equipo sensible</li><li>Suministros dedicados para cargas específicas como variadores o iluminación</li></ul><p>Están presentes en múltiples niveles dentro de un sistema de potencia.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li><p><strong>Capacidad de potencia</strong><br> Debe coincidir o exceder la demanda de carga esperada</p></li><li><p><strong>Relación de voltaje</strong><br> Definida por los requisitos del sistema en los lados primario y secundario</p></li><li><p><strong>Método de enfriamiento</strong><br> Los diseños de tipo seco o con aceite afectan la instalación y el mantenimiento</p></li><li><p><strong>Impedancia</strong><br> Influye en la regulación de voltaje y los niveles de corriente de cortocircuito</p></li><li><p><strong>Eficiencia y pérdidas</strong><br> Incluye pérdidas en el núcleo y pérdidas por carga, importantes para operación continua</p></li><li><p><strong>Entorno de instalación</strong><br> Uso en interiores o exteriores, temperatura, ventilación y requisitos de seguridad</p></li></ul><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>Los transformadores operan de forma continua, por lo que la eficiencia tiene un impacto significativo en el consumo de energía</li><li>El sobredimensionamiento aumenta el costo y las pérdidas en vacío</li><li>El subdimensionamiento provoca sobrecalentamiento y reducción de la vida útil</li><li>La puesta a tierra y la protección adecuadas son críticas para una operación segura</li><li>La ubicación cercana a las cargas reduce la caída de voltaje y los costos de cableado</li></ul>',26)])])}const f=a(s,[["render",r]]);export{m as __pageData,f as default};
